#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <cuda_runtime.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

#define CUDA_CHECK(err) \
  do { \
    if (err != cudaSuccess) { \
      fprintf(stderr, "CUDA Error: %s\n", cudaGetErrorString(err)); \
      exit(EXIT_FAILURE); \
    } \
  } while (0)

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_kernel(const T * __restrict__ mask,
                              const T * __restrict__ in,
                              T * __restrict__ out,
                              const int input_width,
                              const int mask_width)
{
  int i = blockIdx.x * blockDim.x + threadIdx.x;
  if (i >= input_width) return;

  int start = i - mask_width / 2;
  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    int idx = start + j;
    if (idx >= 0 && idx < input_width) {
      s += in[idx] * mask[j];
    }
  }
  out[i] = s;
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel(const T *__restrict__ mask,
                                    const T *__restrict__ in,
                                    T *__restrict__ out,
                                    const int input_width,
                                    const int mask_width)
{
  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  if (i >= input_width) return;

  extern T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];

  int n = mask_width / 2;

  // Load left halo
  int halo_left = (bid - 1) * dim + lid;
  if (lid >= dim - n) {
    tile[lid - (dim - n)] = (halo_left < 0 || halo_left >= input_width) ? 0 : in[halo_left];
  }

  // Load current element
  tile[n + lid] = in[bid * dim + lid];

  // Load right halo
  int halo_right = (bid + 1) * dim + lid;
  if (lid < n) {
    tile[lid + dim + n] = (halo_right >= input_width || halo_right < 0) ? 0 : in[halo_right];
  }

  __syncthreads();

  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    s += tile[lid + j] * mask[j];
  }

  out[i] = s;
}

// Helper to declare static shared memory for tiled kernel
template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel_wrapper(const T *__restrict__ mask,
                                            const T *__restrict__ in,
                                            T *__restrict__ out,
                                            const int input_width,
                                            const int mask_width)
{
  extern __shared__ T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];
  conv1d_tiled_kernel<T, BLOCK_SIZE>(mask, in, out, input_width, mask_width);
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_caching_kernel(const T *__restrict__ mask,
                                            const T *__restrict__ in,
                                            T *__restrict__ out,
                                            const int input_width,
                                            const int mask_width)
{
  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  if (i >= input_width) return;

  extern T tile[BLOCK_SIZE];
  tile[lid] = in[i];

  __syncthreads();

  int this_tile_start = bid * dim;
  int next_tile_start = (bid + 1) * dim;
  int start = i - (mask_width / 2);
  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    int in_index = start + j;
    if (in_index >= 0 && in_index < input_width) {
      if (in_index >= this_tile_start && in_index < next_tile_start) {
        s += tile[lid + j - (mask_width / 2)] * mask[j];
      } else {
        s += in[in_index] * mask[j];
      }
    }
  }
  out[i] = s;
}

// Helper to declare static shared memory for tiled caching kernel
template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_caching_kernel_wrapper(const T *__restrict__ mask,
                                                    const T *__restrict__ in,
                                                    T *__restrict__ out,
                                                    const int input_width,
                                                    const int mask_width)
{
  extern __shared__ T tile[BLOCK_SIZE];
  conv1d_tiled_caching_kernel<T, BLOCK_SIZE>(mask, in, out, input_width, mask_width);
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  cudaMalloc(&a, size_bytes);
  cudaMalloc(&b, size_bytes);

  T *h_a = (T *)malloc(size_bytes);
  T mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    h_a[i] = rand() % 256;
  }

  cudaMemcpy(a, h_a, size_bytes, cudaMemcpyHostToDevice);
  cudaMemcpy(b, mask, mask_width * sizeof(T), cudaMemcpyHostToDevice); // Just to ensure device memory is allocated/touched, though mask is passed separately

  T *d_mask;
  cudaMalloc(&d_mask, mask_width * sizeof(T));
  cudaMemcpy(d_mask, mask, mask_width * sizeof(T), cudaMemcpyHostToDevice);

  // conv1d
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int num_blocks = (input_width + bs - 1) / bs;
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_kernel<T, 64><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  128: {conv1d_kernel<T, 128><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  256: {conv1d_kernel<T, 256><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  512: {conv1d_kernel<T, 512><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case 1024: {conv1d_kernel<T, 1024><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
      }
    }
    cudaDeviceSynchronize();
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel: %f (us)\n",
           (time * 1e-3f) / repeat);

    T *h_b = (T *)malloc(size_bytes);
    cudaMemcpy(h_b, b, size_bytes, cudaMemcpyDeviceToHost);
    reference(h_a, h_b, mask, input_width, mask_width);
    free(h_b);
  }

  // conv1d_tiled
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int num_blocks = input_width / bs;
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_tiled_kernel_wrapper<T, 64><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  128: {conv1d_tiled_kernel_wrapper<T, 128><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  256: {conv1d_tiled_kernel_wrapper<T, 256><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  512: {conv1d_tiled_kernel_wrapper<T, 512><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case 1024: {conv1d_tiled_kernel_wrapper<T, 1024><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
      }
    }
    cudaDeviceSynchronize();
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel: %f (us)\n",
           (time * 1e-3f) / repeat);

    T *h_b = (T *)malloc(size_bytes);
    cudaMemcpy(h_b, b, size_bytes, cudaMemcpyDeviceToHost);
    reference(h_a, h_b, mask, input_width, mask_width);
    free(h_b);
  }

  // conv1d_tiled_caching
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int num_blocks = input_width / bs;
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_tiled_caching_kernel_wrapper<T, 64><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  128: {conv1d_tiled_caching_kernel_wrapper<T, 128><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  256: {conv1d_tiled_caching_kernel_wrapper<T, 256><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case  512: {conv1d_tiled_caching_kernel_wrapper<T, 512><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
        case 1024: {conv1d_tiled_caching_kernel_wrapper<T, 1024><<<<num_blocks, bs>>>(d_mask, a, b, input_width, mask_width); break;}
      }
    }
    cudaDeviceSynchronize();
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel: %f (us)\n",
           (time * 1e-3f) / repeat);

    T *h_b = (T *)malloc(size_bytes);
    cudaMemcpy(h_b, b, size_bytes, cudaMemcpyDeviceToHost);
    reference(h_a, h_b, mask, input_width, mask_width);
    free(h_b);
  }

  cudaFree(a);
  cudaFree(b);
  cudaFree(d_mask);
  free(h_a);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);
  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width);

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
